describe('test-update', function () {
  it('updater receives old value and sets new value', async function () {
    const db = new Dirty();
    db.set('foo', 'bar');
    db.update('foo', (bar) => {
      assert.strictEqual(bar, 'bar');
      return 'baz';
    });
    assert.strictEqual(db.get('foo'), 'baz');
  });
